arguments.new_str:
using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// ── Chat client (MEAI abstraction over OpenAI) ────────────────────────────
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ── Tools ──────────────────────────────────────────────────────────────────
var researchTools = new ResearchTools();
var tools = new List<AITool>
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// ── Agent ──────────────────────────────────────────────────────────────────
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When the user asks about a topic:
        1. Use the SearchWeb tool to find relevant information (make multiple searches with
           different queries to get broad coverage).
        2. Use the SaveNote tool to record each important finding with its source URL.
        3. After gathering enough information, use GetNotes to review everything you collected.
        4. Synthesize the notes into a well-structured summary with source citations.
        Always cite your sources. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools);

// ── Interactive loop ───────────────────────────────────────────────────────
Console.WriteLine("🔬 Research Agent");
Console.WriteLine("   Type a topic to research, or 'quit' to exit.\n");

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("You> ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input))
        continue;
    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    researchTools.ClearNotes();

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("  ⏳ Researching…\n");
    Console.ResetColor();

    try
    {
        var response = await agent.RunAsync(input, session);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.Write("Agent> ");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"  Error: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }
}

Console.WriteLine("Goodbye!");

// ═══════════════════════════════════════════════════════════════════════════
// Tool implementations
// ═══════════════════════════════════════════════════════════════════════════

/// <summary>Tools available to the research agent.</summary>
sealed class ResearchTools
{
    private readonly List<ResearchNote> _notes = [];
    private readonly HttpClient _http = new();
    private static readonly JsonSerializerOptions s_jsonOptions = new() { WriteIndented = true };

    /// <summary>Clears notes between research sessions.</summary>
    public void ClearNotes() => _notes.Clear();

    [Description("Search the web for information on a query. Returns a JSON array of search results with title, URL, and snippet.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://duckduckgo.com/html/?q={encoded}";

            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "ResearchAgent/1.0 (console app; educational)");

            var response = await _http.SendAsync(request);
            var html = await response.Content.ReadAsStringAsync();

            var results = ParseSearchResults(html, query);
            return JsonSerializer.Serialize(results, s_jsonOptions);
        }
        catch (Exception ex)
        {
            return JsonSerializer.Serialize(new
            {
                error = $"Search failed: {ex.Message}",
                suggestion = "Try a different search query."
            });
        }
    }

    [Description("Save a research note. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("The content of the note")] string content,
        [Description("The source URL or reference")] string source)
    {
        var note = new ResearchNote(content, source, DateTime.UtcNow);
        _notes.Add(note);

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved (#{_notes.Count}): {Truncate(content, 60)}");
        Console.ResetColor();

        return $"Note #{_notes.Count} saved successfully.";
    }

