         _notes.Add(note);

         Console.ForegroundColor = ConsoleColor.DarkYellow;
         Console.WriteLine($"  📝 Note saved (#{_notes.Count}): {Truncate(content, 60)}");
         Console.ResetColor();

         return $"Note #{_notes.Count} saved successfully.";
     }

     [Description("Retrieve all saved research notes. Use this to review collected findings before writing a summary.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet. Use SaveNote to record findings first.";

         Console.ForegroundColor = ConsoleColor.DarkYellow;
         Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
         Console.ResetColor();

         return JsonSerializer.Serialize(_notes, s_jsonOptions);
     }

     // ── Helpers ────────────────────────────────────────────────────────────

     private static List<SearchResult> ParseSearchResults(string html, string query)
     {
         var results = new List<SearchResult>();

         // Parse DuckDuckGo HTML results
         var snippetMarker = "result__snippet";
         var titleMarker = "result__a";
         var idx = 0;

         while (results.Count < 5 && idx < html.Length)
         {
             var titleIdx = html.IndexOf(titleMarker, idx, StringComparison.Ordinal);
             if (titleIdx < 0) break;

             var hrefStart = html.LastIndexOf("href=\"", titleIdx, Math.Min(titleIdx, 200), StringComparison.Ordinal);
             var resultUrl = "";
             if (hrefStart >= 0)
             {
                 hrefStart += 6;
                 var hrefEnd = html.IndexOf('"', hrefStart);
                 if (hrefEnd > hrefStart)
                     resultUrl = html[hrefStart..hrefEnd];
             }

             var titleTextStart = html.IndexOf('>', titleIdx) + 1;
             var titleTextEnd = html.IndexOf('<', titleTextStart);
             var title = titleTextEnd > titleTextStart
                 ? StripHtml(html[titleTextStart..titleTextEnd])
                 : "Untitled";

             var snippetIdx = html.IndexOf(snippetMarker, titleIdx, StringComparison.Ordinal);
             var snippet = "";
             if (snippetIdx >= 0)
             {
                 var snippetStart = html.IndexOf('>', snippetIdx) + 1;
                 var snippetEnd = html.IndexOf("</", snippetStart, StringComparison.Ordinal);
                 if (snippetEnd > snippetStart)
                     snippet = StripHtml(html[snippetStart..snippetEnd]);
             }

             if (!string.IsNullOrWhiteSpace(title) && title.Length > 2)
             {
                 results.Add(new SearchResult(title.Trim(), resultUrl.Trim(), snippet.Trim()));
             }

             idx = titleIdx + titleMarker.Length;
         }

         // Fallback when parsing finds nothing
         if (results.Count == 0)
         {
             results.Add(new SearchResult(
                 $"Search results for: {query}",
                 $"https://duckduckgo.com/?q={Uri.EscapeDataString(query)}",
                 "Could not parse individual results. Visit the URL for full results."));
         }

         return results;
     }

     private static string StripHtml(string html)
     {
         var sb = new StringBuilder();
         var inTag = false;
         foreach (var ch in html)
         {
             if (ch == '<') { inTag = true; continue; }
             if (ch == '>') { inTag = false; continue; }
             if (!inTag) sb.Append(ch);
         }
         return System.Net.WebUtility.HtmlDecode(sb.ToString());
     }

     private static string Truncate(string text, int maxLength) =>
         text.Length <= maxLength ? text : string.Concat(text.AsSpan(0, maxLength - 1), "…");
 }

